// ── Prepara resultado unificado para os nós downstream ────────────────────
const wh  = $('Webhook').first().json.body;
const evo = $input.first().json;

// Função helper para limpar strings (remove whitespace/newlines)
const clean = (v) => (typeof v === 'string' ? v.trim() : (v || ''));

// Evolution retorna { key: { remoteJid, fromMe, id }, ... } em caso de sucesso
const success = evo.key !== undefined && evo.key !== null && evo.error === undefined;

return [{
  json: {
    conversationId:      clean(wh.conversationId),
    companyId:           clean(wh.companyId),
    contactIdentifier:   clean(wh.contactIdentifier),
    content:             clean(wh.content),
    agentId:             clean(wh.agentId),
    instanceName:        clean(wh.instanceName),
    success:             success,
    evolutionMessageId:  success ? evo.key.id  : null,
    evolutionError:      success ? null : JSON.stringify(evo.error || evo)
  }
}];

